class Solution:
    def rob(self, root):
        """
        :type root: Optional[TreeNode]
        :rtype: int
        """
        def dfs(node):
            # Returns (max with node, max without node)
            if not node:
                return (0, 0)

            left_with, left_without = dfs(node.left)
            right_with, right_without = dfs(node.right)

            # If rob this node, can't rob children
            rob_this = node.val + left_without + right_without

            # If don't rob this node, can rob or not rob children
            not_rob_this = max(left_with, left_without) + max(right_with, right_without)

            return (rob_this, not_rob_this)

        rob_max, not_rob_max = dfs(root)
        return max(rob_max, not_rob_max)
